-- SPEC:D.2 — compiled metric view: ltv_realized (v1) @ grain=all · entity=semantic_customer
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_ltv_realized_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    SUM(lifetime_value_minor) AS lifetime_value_minor,
    COUNT(DISTINCT brain_id) AS customer_count
  FROM iceberg.brain_serving.semantic_customer
  WHERE identity_basis = 'deterministic'
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2
)
SELECT
  brand_id,
  currency_code,
  lifetime_value_minor,
  customer_count,
  (lifetime_value_minor / NULLIF(customer_count, 0)) AS ltv_realized
FROM base;
